//! User management — SQL ops + token generation/hashing.
//!
//! ## Token storage rationale
//!
//! Tokens are 32 bytes of OS CSPRNG (256 bits of entropy), URL-safe
//! base64-encoded for transport. The stored digest is
//! `SHA-256(token || ":" || pepper)` where `pepper` is a per-server
//! secret kept in `[auth].token_pepper` (auto-generated by
//! `engram init`).
//!
//! Why SHA-256, not argon2id:
//!
//! - **Brute force is infeasible regardless of hash strength.** 2^256
//!   search space dwarfs any plausible offline campaign. Argon2id's slow
//!   hashing buys nothing against tokens of this entropy.
//! - **Per-request lookup is the hot path.** SHA-256 is deterministic →
//!   indexed `UNIQUE` lookup is O(1). Argon2id's per-hash salt would
//!   force an O(N) scan + hash-compare per request, or a separate
//!   deterministic index column that argon2id was meant to replace.
//! - **The realistic threat is DB-only theft.** An attacker without the
//!   config can't reconstruct any token because the pepper isn't in the
//!   stolen rows. (An attacker with both the DB *and* the config has
//!   tokens directly anyway — argon2id wouldn't help.)
//!
//! Token comparison in the auth path uses [`subtle::ConstantTimeEq`]
//! to side-step timing attacks against the hash compare.
//!
//! ## Function layout
//!
//! Each function takes a `&Connection` (or `&Transaction`) and returns
//! a `StoreResult`. The writer actor owns the connection; these
//! functions don't open or close it. The lookup functions take
//! `&Connection` for read-pool use. See module-level tests for the
//! intended call shapes.

use base64::Engine;
use base64::engine::general_purpose::URL_SAFE_NO_PAD;
use engram_core::{NewUser, User, UserId};
use jiff::Timestamp;
use rusqlite::{Connection, OptionalExtension, params};
use sha2::{Digest, Sha256};
use subtle::ConstantTimeEq;

use crate::error::{StoreError, StoreResult};

/// Length of a SHA-256 digest in bytes. The `users.token_hash` column
/// stores exactly this many bytes per row.
pub const TOKEN_HASH_LEN: usize = 32;

/// Length of a raw token in bytes (256 bits of entropy). The
/// URL-safe-base64-encoded form returned by [`generate_token`] is 43
/// characters (32 bytes → ⌈32*4/3⌉ = 43 unpadded chars).
pub const TOKEN_RAW_LEN: usize = 32;

/// Per-server token pepper, newtyped to keep it from being mixed up with
/// other secrets at call sites. Carries the secret read from
/// `[auth].token_pepper` in config; clone is cheap (small `String`).
#[derive(Debug, Clone)]
pub struct TokenPepper {
    inner: String,
}

impl TokenPepper {
    /// Wrap a config-loaded pepper. The caller's responsibility to
    /// ensure it carries enough entropy — `engram init` generates
    /// a 32-byte CSPRNG hex-encoded pepper by default.
    #[must_use]
    pub fn new(s: impl Into<String>) -> Self {
        Self { inner: s.into() }
    }

    /// Bytes used as the second argument to the hash. The `:` separator
    /// in [`hash_token`] lives outside this method so callers can't
    /// accidentally omit it.
    fn as_bytes(&self) -> &[u8] {
        self.inner.as_bytes()
    }
}

/// Hash a plaintext token to its storage digest.
///
/// Layout: `SHA-256(token || ":" || pepper)`. The literal `:` byte
/// between the two inputs prevents the (cosmetic but real)
/// `token || pepper` ambiguity where some `(t1, p1)` and `(t2, p2)`
/// pairs would otherwise collide if `t1 || p1 == t2 || p2`.
#[must_use]
pub fn hash_token(token: &str, pepper: &TokenPepper) -> [u8; TOKEN_HASH_LEN] {
    let mut hasher = Sha256::new();
    hasher.update(token.as_bytes());
    hasher.update(b":");
    hasher.update(pepper.as_bytes());
    hasher.finalize().into()
}

/// Constant-time comparison of a fresh hash against a stored row hash.
/// Equivalent to `==` for correctness; differs in timing characteristics.
#[must_use]
pub fn constant_time_eq(a: &[u8], b: &[u8]) -> bool {
    a.ct_eq(b).into()
}

/// Generate a fresh URL-safe-base64 token. 32 bytes of OS CSPRNG, 43
/// characters of output (unpadded). The caller is expected to display
/// this exactly once (returning it from `POST /admin/users` or
/// `POST /admin/users/:username/rotate-token`) and never store it.
///
/// # Errors
/// Returns [`StoreError::Os`] if the OS CSPRNG read fails. In practice
/// this only happens on misconfigured embedded platforms.
pub fn generate_token() -> StoreResult<String> {
    let mut bytes = [0u8; TOKEN_RAW_LEN];
    getrandom::fill(&mut bytes)
        .map_err(|e| StoreError::Os(format!("os csprng failed during token generation: {e}")))?;
    Ok(URL_SAFE_NO_PAD.encode(bytes))
}

// ── SQL ops ────────────────────────────────────────────────────────

/// Insert a fresh user row. `new_user` MUST have been validated by
/// [`NewUser::validate`](engram_core::NewUser::validate) before this
/// call; the writer actor owns that pre-flight.
///
/// # Errors
/// - [`StoreError::Duplicate`] when `username` or `email` clashes with
///   an existing row (UNIQUE violation).
/// - [`StoreError::Sql`] for any other SQL failure.
pub fn insert_user(
    conn: &Connection,
    new_user: &NewUser,
    token_hash: &[u8; TOKEN_HASH_LEN],
) -> StoreResult<UserId> {
    let id = UserId::new();
    let now = Timestamp::now().as_microsecond();
    conn.execute(
        "INSERT INTO users \
         (id, username, name, email, token_hash, created_at) \
         VALUES (?1, ?2, ?3, ?4, ?5, ?6)",
        params![
            id.as_bytes(),
            &new_user.username,
            &new_user.name,
            &new_user.email,
            token_hash.as_slice(),
            now,
        ],
    )
    .map_err(map_unique_violation)?;
    Ok(id)
}

/// Replace the user's `token_hash` with a freshly-generated digest, and
/// clear `token_expired_at` (rotating a token only makes sense to make
/// it usable again). Returns whether a row was actually updated; `false`
/// means the user id didn't exist.
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure other than the
/// "no row matched" case (which is reported as `Ok(false)`).
pub fn rotate_user_token(
    conn: &Connection,
    id: UserId,
    new_token_hash: &[u8; TOKEN_HASH_LEN],
) -> StoreResult<bool> {
    let rows = conn.execute(
        "UPDATE users SET token_hash = ?1, token_expired_at = NULL WHERE id = ?2",
        params![new_token_hash.as_slice(), id.as_bytes()],
    )?;
    Ok(rows > 0)
}

/// Stamp `token_expired_at = now()` — the user's current token stops
/// authenticating but the row stays put so historical attribution
/// references remain valid. Idempotent: expiring an already-expired
/// token returns `Ok(true)` and leaves `token_expired_at` unchanged.
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure.
pub fn expire_user_token(conn: &Connection, id: UserId) -> StoreResult<bool> {
    let now = Timestamp::now().as_microsecond();
    let rows = conn.execute(
        "UPDATE users SET token_expired_at = COALESCE(token_expired_at, ?1) WHERE id = ?2",
        params![now, id.as_bytes()],
    )?;
    Ok(rows > 0)
}

/// Clear `token_expired_at`, re-activating the user's existing token.
/// Idempotent: reviving an already-active token is a no-op.
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure.
pub fn revive_user_token(conn: &Connection, id: UserId) -> StoreResult<bool> {
    let rows = conn.execute(
        "UPDATE users SET token_expired_at = NULL WHERE id = ?1",
        params![id.as_bytes()],
    )?;
    Ok(rows > 0)
}

/// Update `last_seen_at = now()` for the user. Called fire-and-forget
/// by the auth middleware on every authenticated request; never blocks
/// the response. Returns `Ok(false)` when the row doesn't exist (the
/// caller authenticated against a token whose user was deleted
/// mid-request — already a logic error elsewhere).
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure.
pub fn touch_user_last_seen(conn: &Connection, id: UserId) -> StoreResult<bool> {
    let now = Timestamp::now().as_microsecond();
    let rows = conn.execute(
        "UPDATE users SET last_seen_at = ?1 WHERE id = ?2",
        params![now, id.as_bytes()],
    )?;
    Ok(rows > 0)
}

/// Look up the user that owns `token_hash` IF the token is currently
/// active (`token_expired_at IS NULL`). Hot path for the auth
/// middleware.
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure other than "no row
/// matched" (which is reported as `Ok(None)`).
pub fn find_active_user_by_token_hash(
    conn: &Connection,
    token_hash: &[u8; TOKEN_HASH_LEN],
) -> StoreResult<Option<User>> {
    conn.query_row(
        "SELECT id, username, name, email, created_at, last_seen_at, token_expired_at \
         FROM users WHERE token_hash = ?1 AND token_expired_at IS NULL",
        params![token_hash.as_slice()],
        row_to_user,
    )
    .optional()
    .map_err(StoreError::from)
}

/// Look up a user by exact-match username. Used by the admin endpoints
/// (`expire`, `revive`, `rotate-token` all accept username on the wire).
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure other than "no row
/// matched" (`Ok(None)`).
pub fn find_user_by_username(conn: &Connection, username: &str) -> StoreResult<Option<User>> {
    conn.query_row(
        "SELECT id, username, name, email, created_at, last_seen_at, token_expired_at \
         FROM users WHERE username = ?1",
        params![username],
        row_to_user,
    )
    .optional()
    .map_err(StoreError::from)
}

/// Look up a user by id. **Returns even users whose token is expired**
/// — needed by the attribution display path (we still want to render
/// "alice wrote this last month" after alice's token has been expired).
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure other than "no row
/// matched" (`Ok(None)`).
pub fn find_user_by_id(conn: &Connection, id: UserId) -> StoreResult<Option<User>> {
    conn.query_row(
        "SELECT id, username, name, email, created_at, last_seen_at, token_expired_at \
         FROM users WHERE id = ?1",
        params![id.as_bytes()],
        row_to_user,
    )
    .optional()
    .map_err(StoreError::from)
}

/// All users, ordered by `created_at` ascending. Used by
/// `GET /admin/users` / `engram user list`. Includes users whose
/// token is expired (the CLI surfaces the active/expired flag from
/// `token_expired_at`).
///
/// # Errors
/// Returns [`StoreError::Sql`] for any SQL failure.
pub fn list_users(conn: &Connection) -> StoreResult<Vec<User>> {
    let mut stmt = conn.prepare(
        "SELECT id, username, name, email, created_at, last_seen_at, token_expired_at \
         FROM users ORDER BY created_at ASC",
    )?;
    let rows = stmt
        .query_map([], row_to_user)?
        .collect::<Result<Vec<_>, _>>()?;
    Ok(rows)
}

// ── helpers ────────────────────────────────────────────────────────

fn row_to_user(row: &rusqlite::Row<'_>) -> rusqlite::Result<User> {
    let id_bytes: Vec<u8> = row.get(0)?;
    let id = UserId::from_slice(&id_bytes).map_err(|e| {
        rusqlite::Error::FromSqlConversionFailure(
            0,
            rusqlite::types::Type::Blob,
            Box::new(std::io::Error::other(e.to_string())),
        )
    })?;
    Ok(User {
        id,
        username: row.get(1)?,
        name: row.get(2)?,
        email: row.get(3)?,
        created_at: row.get(4)?,
        last_seen_at: row.get(5)?,
        token_expired_at: row.get(6)?,
    })
}

/// Map SQLite UNIQUE-violation errors to a typed `Duplicate`. Anything
/// else passes through verbatim. The CLI / admin endpoint relies on
/// this to render a readable "username already taken" message.
fn map_unique_violation(e: rusqlite::Error) -> StoreError {
    if let rusqlite::Error::SqliteFailure(sqlite_err, msg) = &e
        && sqlite_err.code == rusqlite::ErrorCode::ConstraintViolation
    {
        let text = msg.clone().unwrap_or_else(|| sqlite_err.to_string());
        // SQLite reports `UNIQUE constraint failed: users.username`
        // (or `users.email`); the substring is stable across versions.
        if text.contains("users.username") {
            return StoreError::Duplicate("username already taken".into());
        }
        if text.contains("users.email") {
            return StoreError::Duplicate("email already in use".into());
        }
        if text.contains("users.token_hash") {
            return StoreError::Duplicate("token hash collision".into());
        }
        return StoreError::Duplicate(text);
    }
    StoreError::from(e)
}

#[cfg(test)]
mod tests {
    use super::*;
    use engram_core::NewUser;
    use rusqlite::Connection;

    fn fresh_conn() -> Connection {
        let mut conn = Connection::open_in_memory().unwrap();
        conn.pragma_update(None, "foreign_keys", "ON").unwrap();
        crate::migrations::run(&mut conn).expect("migrations::run");
        conn
    }

    fn pepper() -> TokenPepper {
        TokenPepper::new("test-pepper-1234567890abcdef")
    }

    fn sample_new_user(name: &str) -> NewUser {
        NewUser {
            username: name.to_string(),
            name: None,
            email: None,
        }
    }

    #[test]
    fn hash_token_is_deterministic_and_isolates_pepper() {
        let p = pepper();
        let h1 = hash_token("hunter2", &p);
        let h2 = hash_token("hunter2", &p);
        assert_eq!(h1, h2, "same input → same hash");

        let p2 = TokenPepper::new("different-pepper");
        let h3 = hash_token("hunter2", &p2);
        assert_ne!(h1, h3, "different pepper → different hash");

        let h4 = hash_token("hunter3", &p);
        assert_ne!(h1, h4, "different token → different hash");
    }

    #[test]
    fn hash_token_separator_blocks_ambiguous_concatenation() {
        // Without the `:` separator, ("ab", "cd") and ("abc", "d") would
        // hash the same input. The separator prevents that.
        let p1 = TokenPepper::new("cd");
        let p2 = TokenPepper::new("d");
        let h1 = hash_token("ab", &p1);
        let h2 = hash_token("abc", &p2);
        assert_ne!(h1, h2);
    }

    #[test]
    fn generate_token_emits_url_safe_base64_of_expected_length() {
        let tok = generate_token().unwrap();
        // URL-safe-no-pad of 32 bytes is 43 chars (`(32*8+5)/6 = 43`).
        assert_eq!(tok.len(), 43);
        assert!(
            tok.chars()
                .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
        );
    }

    #[test]
    fn generate_token_is_unique_per_call() {
        let a = generate_token().unwrap();
        let b = generate_token().unwrap();
        assert_ne!(a, b);
    }

    #[test]
    fn insert_then_find_by_username_round_trip() {
        let conn = fresh_conn();
        let p = pepper();
        let hash = hash_token("the-token", &p);

        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let id = insert_user(&conn, &nu, &hash).unwrap();

        let found = find_user_by_username(&conn, "alice").unwrap().unwrap();
        assert_eq!(found.id, id);
        assert_eq!(found.username, "alice");
        assert!(found.is_token_active());
    }

    #[test]
    fn insert_rejects_duplicate_username() {
        let conn = fresh_conn();
        let p = pepper();
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();

        let h1 = hash_token("token-a", &p);
        let h2 = hash_token("token-b", &p);
        insert_user(&conn, &nu, &h1).unwrap();
        let err = insert_user(&conn, &nu, &h2).unwrap_err();
        assert!(
            matches!(&err, StoreError::Duplicate(m) if m.contains("username")),
            "expected Duplicate(username), got {err:?}"
        );
    }

    #[test]
    fn insert_rejects_duplicate_email_case_insensitive() {
        let conn = fresh_conn();
        let p = pepper();
        let mut a = NewUser {
            username: "alice".into(),
            name: None,
            email: Some("Alice@Example.com".into()),
        };
        a.validate().unwrap();
        insert_user(&conn, &a, &hash_token("ta", &p)).unwrap();

        let mut b = NewUser {
            username: "bob".into(),
            name: None,
            email: Some("ALICE@example.COM".into()),
        };
        b.validate().unwrap();
        // Both lowercased to `alice@example.com` — UNIQUE COLLATE NOCASE
        // catches it even without the validation lowercase.
        let err = insert_user(&conn, &b, &hash_token("tb", &p)).unwrap_err();
        assert!(matches!(&err, StoreError::Duplicate(m) if m.contains("email")));
    }

    #[test]
    fn find_active_user_by_token_hash_returns_only_active() {
        let conn = fresh_conn();
        let p = pepper();
        let token = "live-token";
        let hash = hash_token(token, &p);
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let id = insert_user(&conn, &nu, &hash).unwrap();

        // Active → returns Some.
        let found = find_active_user_by_token_hash(&conn, &hash).unwrap();
        assert_eq!(found.unwrap().id, id);

        // After expire → returns None.
        let updated = expire_user_token(&conn, id).unwrap();
        assert!(updated);
        let found = find_active_user_by_token_hash(&conn, &hash).unwrap();
        assert!(
            found.is_none(),
            "expired user must NOT come back from active-token lookup"
        );
    }

    #[test]
    fn find_user_by_id_returns_even_expired_users() {
        // Critical for attribution: a page authored by alice last
        // month must still display "alice" today even after alice's
        // token has been expired.
        let conn = fresh_conn();
        let p = pepper();
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let id = insert_user(&conn, &nu, &hash_token("t", &p)).unwrap();
        expire_user_token(&conn, id).unwrap();

        let found = find_user_by_id(&conn, id).unwrap().unwrap();
        assert_eq!(found.id, id);
        assert!(found.token_expired_at.is_some());
        assert!(!found.is_token_active());
    }

    #[test]
    fn expire_is_idempotent_preserving_original_timestamp() {
        let conn = fresh_conn();
        let p = pepper();
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let id = insert_user(&conn, &nu, &hash_token("t", &p)).unwrap();

        expire_user_token(&conn, id).unwrap();
        let first = find_user_by_id(&conn, id)
            .unwrap()
            .unwrap()
            .token_expired_at;
        assert!(first.is_some());

        // Second expire call must not move the timestamp forward —
        // COALESCE in the UPDATE keeps the original.
        expire_user_token(&conn, id).unwrap();
        let second = find_user_by_id(&conn, id)
            .unwrap()
            .unwrap()
            .token_expired_at;
        assert_eq!(first, second, "expire must be idempotent");
    }

    #[test]
    fn revive_clears_expiration() {
        let conn = fresh_conn();
        let p = pepper();
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let id = insert_user(&conn, &nu, &hash_token("t", &p)).unwrap();

        expire_user_token(&conn, id).unwrap();
        assert!(
            !find_user_by_id(&conn, id)
                .unwrap()
                .unwrap()
                .is_token_active()
        );

        revive_user_token(&conn, id).unwrap();
        assert!(
            find_user_by_id(&conn, id)
                .unwrap()
                .unwrap()
                .is_token_active()
        );
    }

    #[test]
    fn rotate_token_issues_new_hash_and_revives() {
        let conn = fresh_conn();
        let p = pepper();
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let h_old = hash_token("old-token", &p);
        let id = insert_user(&conn, &nu, &h_old).unwrap();
        expire_user_token(&conn, id).unwrap();

        let h_new = hash_token("new-token", &p);
        let updated = rotate_user_token(&conn, id, &h_new).unwrap();
        assert!(updated);

        // Old hash no longer authenticates.
        assert!(
            find_active_user_by_token_hash(&conn, &h_old)
                .unwrap()
                .is_none()
        );
        // New hash does — and the user is implicitly revived.
        let found = find_active_user_by_token_hash(&conn, &h_new).unwrap();
        assert_eq!(found.unwrap().id, id);
    }

    #[test]
    fn touch_last_seen_records_timestamp() {
        let conn = fresh_conn();
        let p = pepper();
        let mut nu = sample_new_user("alice");
        nu.validate().unwrap();
        let id = insert_user(&conn, &nu, &hash_token("t", &p)).unwrap();
        assert!(
            find_user_by_id(&conn, id)
                .unwrap()
                .unwrap()
                .last_seen_at
                .is_none(),
            "fresh users have no last_seen_at"
        );

        touch_user_last_seen(&conn, id).unwrap();
        assert!(
            find_user_by_id(&conn, id)
                .unwrap()
                .unwrap()
                .last_seen_at
                .is_some(),
            "touch must populate last_seen_at"
        );
    }

    #[test]
    fn list_users_orders_by_created_at_ascending() {
        let conn = fresh_conn();
        let p = pepper();
        for name in ["alice", "bob", "carol"] {
            let mut nu = sample_new_user(name);
            nu.validate().unwrap();
            insert_user(&conn, &nu, &hash_token(name, &p)).unwrap();
        }
        let users = list_users(&conn).unwrap();
        assert_eq!(users.len(), 3);
        let usernames: Vec<_> = users.iter().map(|u| u.username.as_str()).collect();
        assert_eq!(usernames, vec!["alice", "bob", "carol"]);
    }

    #[test]
    fn rotate_returns_false_for_unknown_user() {
        let conn = fresh_conn();
        let p = pepper();
        let ghost = UserId::new();
        let updated = rotate_user_token(&conn, ghost, &hash_token("x", &p)).unwrap();
        assert!(!updated);
    }

    #[test]
    fn constant_time_eq_matches_plain_eq() {
        let a = [1u8, 2, 3, 4];
        let b = [1u8, 2, 3, 4];
        let c = [1u8, 2, 3, 5];
        assert!(constant_time_eq(&a, &b));
        assert!(!constant_time_eq(&a, &c));
        assert!(!constant_time_eq(&a, &[1u8, 2, 3]));
    }
}
